import sys
input = sys.stdin.read

def main():
    data = input().split()
    H = int(data[0])
    W = int(data[1])
    grid = data[2:2+H]

    # Convert grid to a 2D list of characters
    grid = [list(row) for row in grid]

    # Track which cookies are still present
    present = [[True for _ in range(W)] for _ in range(H)]

    # Mark cookies to be removed
    while True:
        to_remove = set()
        # Step 1: Mark rows
        for i in range(H):
            # Only consider present cookies in the row
            row_chars = [grid[i][j] for j in range(W) if present[i][j]]
            if len(row_chars) >= 2 and len(set(row_chars)) == 1:
                for j in range(W):
                    if present[i][j]:
                        to_remove.add((i, j))

        # Step 2: Mark columns
        for j in range(W):
            # Only consider present cookies in the column
            col_chars = [grid[i][j] for i in range(H) if present[i][j]]
            if len(col_chars) >= 2 and len(set(col_chars)) == 1:
                for i in range(H):
                    if present[i][j]:
                        to_remove.add((i, j))

        # Step 3: Check if any marked cookies
        if not to_remove:
            break

        # Remove marked cookies
        for i, j in to_remove:
            present[i][j] = False

    # Count remaining cookies
    count = 0
    for i in range(H):
        for j in range(W):
            if present[i][j]:
                count += 1
    print(count)

if __name__ == "__main__":
    main()
